from datetime import datetime, timezone, timedelta

with open('/Users/ktoclaw/.hermes/cron/jobs.json') as f:
    d = json.load(f)

now = datetime.now(timezone(timedelta(hours=8)))  # SGT
stale = []
for j in d.get('jobs', []):
    if j.get('schedule', {}).get('kind') == 'once':
        run_at = j.get('schedule', {}).get('run_at')
        name = j.get('name', '?')
        if run_at:
            run_dt = datetime.fromisoformat(run_at.replace('+08:00', '+08:00').replace('Z', '+00:00'))
            if 'T' in run_at and '+08:00' not in run_at and 'Z' not in run_at:
                run_dt = datetime.fromisoformat(run_at).replace(tzinfo=timezone(timedelta(hours=8)))
            elif run_at.endswith('+08:00'):
                run_dt = datetime.fromisoformat(run_at)
            if run_dt < now:
                stale.append(f"STALE: {name} (was {run_at})")
            else:
                print(f"OK: {name} (runs {run_at})")

print(f"\n--- Stale (past-due) one-shot jobs: {len(stale)} ---")
for s in stale:
    print(s)"}

